let triggerTime = parseFloat(msg.payload); // Zeit in Sekunden aus dem input
let timerId = flow.get("timerId") || null; // Holen des Timer-IDs aus dem Flow-Kontext
let endTime = flow.get("endTime") || Date.now() + triggerTime * 1000; // Endzeit aus Flow-Kontext oder neu berechnen
const triggerIntervalSeconds = Math.max(1, triggerTime || 1);

function buildTriggerMeta() {
    return {
        trigger: {
            intervalSeconds: triggerIntervalSeconds,
            intervalMs: triggerIntervalSeconds * 1000
        }
    };
}

// Bestehenden Timer löschen, falls vorhanden
if (timerId) {
    clearInterval(timerId);
}

// Funktion zur Aktualisierung des Node-Status
function updateCountdown() {
    let remainingTime = Math.ceil((endTime - Date.now()) / 1000);
    if (remainingTime > 0) {
        node.status({ fill: "red", shape: "ring", text: `Trigger in ${remainingTime}s` });
    } else {
        node.status({ fill: "green", shape: "dot", text: "Triggered" });
        endTime = Date.now() + triggerIntervalSeconds * 1000; // Neu berechnen des Endzeitpunkts für kontinuierliche Wiederholungen
        node.send({
            payload: true,
            meta: buildTriggerMeta()
        }); // Sende 'true' bei Ablauf des Timers
    }
}

// Setzen des Intervall-Timers
timerId = setInterval(() => {
    updateCountdown();
}, 1000); // Jede Sekunde aktualisieren

// Speichern des Timer-IDs und des Endzeitpunkts im Flow-Kontext
flow.set("timerId", timerId);
flow.set("endTime", endTime);
flow.set("triggerIntervalSeconds", triggerIntervalSeconds);

// Initialer Aufruf zur Statusaktualisierung
updateCountdown();

return null; // Keine direkte Nachrichtenausgabe

// Definier Funktion zur Erstellung der Log-Nachricht
function createLogFileMsg(
    dtuState,
    invStateProducing,
    invStateReachable,
    statusZeroInjection,
    pwrConsumption,
    pwrSecondSource,
    socLevelBattery,
    setPercentMsg,
    turnOnMsg,
    turnOffMsg,
    debugMsg
) {
    const now = new Date();
    const formattedTime = now.toLocaleString("de-DE", { hour12: false }); // Formatiert Zeit als 'Tag.Monat.Jahr Stunden:Minuten:Sekunden'

    // Konvertiert Zahlenwerte zu Strings mit Komma als Dezimaltrennzeichen
    const formattedPwrConsumption = pwrConsumption.toLocaleString("de-DE");
    const formattedPwrSecondSource = pwrSecondSource.toLocaleString("de-DE");

    return {
        payload: {
            time: formattedTime,
            dtuState: dtuState,
            invStateProducing: invStateProducing,
            invStateReachable: invStateReachable,
            statusZeroInjection: statusZeroInjection,
            pwrConsumption: formattedPwrConsumption,
            pwrSecondSource: formattedPwrSecondSource,
            socLevelBattery: socLevelBattery,
            setPercentMsg: setPercentMsg ? setPercentMsg.payload : null,
            turnOnMsg: turnOnMsg ? turnOnMsg.payload : null,
            turnOffMsg: turnOffMsg ? turnOffMsg.payload : null,
            debugMsg: debugMsg.payload
        }
    };
}

// Definiert min und max Prozentwerte für die DTU-Ausgangsleistung
const maxOutputPowerInv = parseFloat(msg.payload.maxOutputPowerInv); // Maximale Ausgangsleistung des Wechselrichters in Watt
const pwrSteps = maxOutputPowerInv / 100; // Berechnet die Leistung pro Prozent
const minOutputZeroInjection = parseFloat(msg.payload.minOutputZeroInjection); // Minimale Leistung in Prozent bei aktivierter Nulleinspeisung
const maxOutputZeroInjection = parseFloat(msg.payload.maxOutputZeroInjection); // Maximale Leistung in Prozent bei aktivierter Nulleinspeisung
const maxOutputAtFullSoc = parseFloat(msg.payload.maxOutputAtFullSoc); // Maximale Ausgangsleistung in Prozent bei vollem Batterie-SoC
const staticInverterOutputPower = parseFloat(msg.payload.staticInverterOutputPower); // Voreingestellte Ausgangsleistung, wenn Nulleinspeisung deaktiviert ist
const minPowerInverter = minOutputZeroInjection * pwrSteps; // Berechnet die minimale Leistung in Watt, basierend auf dem Prozentwert und den Leistungsschritten

// Definiert Schwellenwerte für den Batterie-SoC
const offThresholdInv = parseFloat(msg.payload.offThresholdInv); // Batterie-SoC-Schwelle zum Ausschalten des Wechselrichters
const onThresholdInv = parseFloat(msg.payload.onThresholdInv); // Batterie-SoC-Schwelle zum Einschalten des Wechselrichters

// Extrahiert Daten aus msg.payload für Steuerungsentscheidungen
const dtuState = msg.payload.dtuState; // Der aktuelle Betriebszustand der DTU (Datenübertragungseinheit)
const pwrSecondSource = parseFloat(msg.payload.pwrSecondSource); // Leistung der zweiten Energiequelle in Watt
const pwrConsumption = parseFloat(msg.payload.pwrConsumption); // Aktueller Gesamtstromverbrauch in Watt
const invStateProducing = msg.payload.invStateProducing; // Gibt an, ob der Wechselrichter aktuell Strom produziert
const invStateReachable = msg.payload.invStateReachable; // Verfügbarkeitsstatus des Wechselrichters
const socLevelBattery = parseFloat(msg.payload.socLevelBattery); // Der aktuelle Ladezustand der Batterie in Prozent
const statusZeroInjection = msg.payload.statusZeroInjection; // Aktueller Status der Nulleinspeisung ('on' oder 'off')

// Entscheidungslogik für die Ausgabe der Befehle basierend auf dem Zustand und den Messdaten
let setPercentMsg = null;
let turnOnMsg = null;
let turnOffMsg = null;
let debugMsg = null;

// Steuerung basierend auf dem Status der Nulleinspeisung
if (statusZeroInjection !== "on") {
    if (invStateProducing === "on") {
        setPercentMsg = { payload: staticInverterOutputPower };
        debugMsg = { payload: "Nulleinspeisung deaktiviert, statische Leistung angewendet" };
    } else {
        debugMsg = { payload: "Nulleinspeisung deaktiviert, Wechselrichter aus" };
    }
    const logFileMsg = createLogFileMsg(
        dtuState,
        invStateProducing,
        invStateReachable,
        statusZeroInjection,
        pwrConsumption,
        pwrSecondSource,
        socLevelBattery,
        setPercentMsg,
        turnOnMsg,
        turnOffMsg,
        debugMsg
    );
    return [setPercentMsg, turnOnMsg, turnOffMsg, debugMsg, logFileMsg];
} else {
    debugMsg = { payload: "Nulleinspeisung aktiviert" };
}

// Überprüft die Erreichbarkeit und Betriebsbereitschaft der Systemkomponenten
if (dtuState !== "on" || invStateReachable !== "on") {
    debugMsg = { payload: `DTU offline oder Wechselrichter nicht erreichbar` };
    const logFileMsg = createLogFileMsg(
        dtuState,
        invStateProducing,
        invStateReachable,
        statusZeroInjection,
        pwrConsumption,
        pwrSecondSource,
        socLevelBattery,
        setPercentMsg,
        turnOnMsg,
        turnOffMsg,
        debugMsg
    );
    return [null, null, null, debugMsg, logFileMsg];
} else {
    debugMsg = { payload: `DTU und Wechselrichter sind online` };
}

// Berechnet die erforderliche Leistungskorrektur basierend auf dem aktuellen Verbrauch und der Zweitquelle
let powerDifference = pwrConsumption - pwrSecondSource;

// Steuerung des Wechselrichters basierend auf dem Batterie-SoC und der Differenzleistung
if (socLevelBattery <= offThresholdInv && invStateProducing === "on") {
    turnOffMsg = { payload: "OFF" };
    const logFileMsg = createLogFileMsg(
        dtuState,
        invStateProducing,
        invStateReachable,
        statusZeroInjection,
        pwrConsumption,
        pwrSecondSource,
        socLevelBattery,
        setPercentMsg,
        turnOnMsg,
        turnOffMsg,
        debugMsg
    );
    return [setPercentMsg, turnOnMsg, turnOffMsg, debugMsg, logFileMsg];
} else {
    // Zuerst wird überprüft, ob der Wechselrichter Strom produziert
    if (invStateProducing === "on") {
        if (powerDifference < minPowerInverter) {
            // Sendet ein Signal, um den Wechselrichter auszuschalten, falls die Differenzleistung unter dem Mindestniveau liegt
            turnOffMsg = { payload: "OFF" };
        } else {
            // Berechnet den erforderlichen Leistungsprozentsatz, wenn keine Ausschaltanforderung vorliegt
            let requiredPercent = Math.floor(powerDifference / pwrSteps);
            let effectiveMaxOutput =
                socLevelBattery === 100 ? maxOutputAtFullSoc : maxOutputZeroInjection;
            requiredPercent = Math.max(
                minOutputZeroInjection,
                Math.min(requiredPercent, effectiveMaxOutput)
            );
            setPercentMsg = { payload: requiredPercent };
        }
    } else if (socLevelBattery >= onThresholdInv && powerDifference >= minPowerInverter) {
        // Überprüft, ob der Batterie-SoC oberhalb des Schwellenwertes liegt und die Differenzleistung ausreichend ist
        let requiredPercent = Math.floor(powerDifference / pwrSteps);
        let effectiveMaxOutput =
            socLevelBattery === 100 ? maxOutputAtFullSoc : maxOutputZeroInjection;
        requiredPercent = Math.max(
            minOutputZeroInjection,
            Math.min(requiredPercent, effectiveMaxOutput)
        );
        setPercentMsg = { payload: requiredPercent };
        turnOnMsg = { payload: "ON" };
    } else {
        // Keine Aktion erforderlich, da der Wechselrichter aus ist und die Bedingungen zum Einschalten nicht erfüllt sind
        debugMsg = {
            payload: "Wechselrichter bleibt aus - Bedingungen zum Einschalten nicht erfüllt"
        };
    }
}

const logFileMsg = createLogFileMsg(
    dtuState,
    invStateProducing,
    invStateReachable,
    statusZeroInjection,
    pwrConsumption,
    pwrSecondSource,
    socLevelBattery,
    setPercentMsg,
    turnOnMsg,
    turnOffMsg,
    debugMsg
);
// Rückgabe der Steuerbefehle
return [setPercentMsg, turnOnMsg, turnOffMsg, debugMsg, logFileMsg];

// 1. DATA RETRIEVAL
function getFirstFinite(values, fallback = 0) {
    for (const value of values) {
        if (Number.isFinite(value)) {
            return value;
        }
    }

    return fallback;
}

const gridPower = getFirstFinite([msg.data?.grid?.power], 0);
const maxChargePower = getFirstFinite(
    [msg.data?.battery?.chargeHardwareMaxPower, msg.data?.battery?.chargeMaxPower],
    800
);
const batteryInflow = getFirstFinite([msg.data?.battery?.chargePower], 0);
const calculatedDemand = getFirstFinite([msg.derived?.demand?.defensiveTarget], 0);
const liveSolarPower = getFirstFinite(
    [msg.derived?.solar?.livePower, msg.data?.solar?.totalPower],
    0
);
const stableSolarPower = getFirstFinite(
    [msg.derived?.solar?.averagePower, liveSolarPower],
    liveSolarPower
);
const solarLiveBlend = 0.35; // Pull part of the live solar into the stable value on cloudy days
const effectiveSolarPower = Math.max(
    stableSolarPower,
    liveSolarPower * solarLiveBlend + stableSolarPower * (1 - solarLiveBlend)
);
const soc = getFirstFinite([msg.data?.battery?.soc], 0);
const minSoc = getFirstFinite([msg.data?.battery?.minSoc], 15);
const currentSetInflow = getFirstFinite([msg.data?.battery?.chargeSetpoint], 0);
const totalProduced = getFirstFinite([msg.data?.solar?.totalPower], 0);
const solarSecondaryPower = getFirstFinite([msg.data?.solar?.secondaryPower], 0);
const demandTiming = msg.meta?.sensorTiming?.demand;
const demandTimingThresholds = msg.meta?.sensorTiming?.thresholds || {};
const demandConfidence = demandTiming?.confidence;
const reliableDemandConfidence = Number.isFinite(demandTimingThresholds.reliableConfidence)
    ? demandTimingThresholds.reliableConfidence
    : 0.7;
const gridTimingReading = demandTiming?.sensors?.grid;
const normalization = msg.meta?.normalization;
const normalizationReadings = normalization?.readings || {};
const gridNormalizationReading = normalizationReadings.gridPower;
const solarNormalizationReadings = [
    normalizationReadings.solarPrimaryPower,
    normalizationReadings.solarSecondaryPower
];
const stability = msg.meta?.stability || {};

function readingHasLowConfidence(reading) {
    if (!reading) {
        return false;
    }

    return (
        reading.isValid === false ||
        reading.isStale === true ||
        reading.usedLastValid === true ||
        reading.usedFallback === true
    );
}

// 2. CONFIGURATION (Based on safety buffer strategy)
// this addresses the "Moving Target" problem with huge latencies of smart meter and battery chargine changes:
const targetBuffer = 30; // Aim for 30W import
const maxInverterPower = 1200; // the Inverter limit
const minSustain = 50; // Keep charging circuit active
const exportTolerance = 5; // Ignore tiny meter jitter, react to real export quickly
const exportBoostFactor = 1.25; // Compensate for meter/inverter latency when exporting
const solarSwitchGuardFactor = 0.5; // Avoid charge relay cycling while solar is still available
const unstableSolarMaxIncreaseW = 250; // Cloud flicker: do not chase export spikes too hard
const unstableSolarMaxDecreaseW = 250; // Cloud flicker: avoid relay/setpoint whiplash on brief shade
const unstableSolarEmergencyImportW = 1500; // Still back off fast if we are clearly charging from grid
const lowSocMildImportThresholdW = 200; // At minimum SoC, mild import is not enough reason to stop
const lowSocPositiveSurplusImportThresholdW = 1000; // Positive solar surplus means imports may be lag
const lowSocReserveMargin = 2; // Treat the first percent points above min SoC as fragile recovery
const lowSocMaxDecreaseW = 250; // Keep minimum-SoC recovery from collapsing on one cloudy sample

// calculated Demand is the brutto demand of power, solar power the generated and usable power.
// default expects that there is more solar power than demand,
// e.g. 1000W (solar) - 300W (demand) + 30W buffer = 730W to charge
//      300W (solar) - 350W (demand) + 30W buffer = -20W hardly necessary to charge
//      200W (solar) - 200W (demand) + 30W buffer = 30W to charge
//        0W (solar) - 200W (demand) + 30W buffer = -170W do not charge
//        1W (solar) - 201W (demand) + 30W buffer = -170W stop charging
//  --- SAFETY RULES & CLAMPING
let clampReason = "None";
let ruleApplied = "None";
const isExporting = gridPower < -exportTolerance;
const solarIsUnstable =
    stability.solar === "unstable" ||
    stability.mode === "solar_unstable" ||
    stability.mode === "unstable_unstable";
let lastCommand = context.get("lastCommand") || 0;
const lastDemandEstimate = context.get("lastDemandEstimate");

const demandSnapshotReliable =
    (!Number.isFinite(demandConfidence) || demandConfidence >= reliableDemandConfidence) &&
    normalization?.plausibility?.isConsistent !== false &&
    !solarNormalizationReadings.some(readingHasLowConfidence);
const gridSnapshotReliable =
    gridTimingReading?.isValid !== false && !readingHasLowConfidence(gridNormalizationReading);
const shouldFreezeCommand = !gridSnapshotReliable || !Number.isFinite(gridPower);

if (shouldFreezeCommand) {
    const lastSolarSecondaryPower = context.get("lastSolarSecondaryPower");
    const solarSecondaryIncrease = Number.isFinite(lastSolarSecondaryPower)
        ? solarSecondaryPower - lastSolarSecondaryPower
        : 0;
    const secondarySolarSnapshotReliable = !readingHasLowConfidence(
        normalizationReadings.solarSecondaryPower
    );

    if (secondarySolarSnapshotReliable && solarSecondaryIncrease > targetBuffer) {
        ruleApplied = "Low-Confidence Solar Increase";
        const holdCommand = Math.round(Math.max(lastCommand, currentSetInflow, batteryInflow, 0));
        const targetCharge = holdCommand + solarSecondaryIncrease * 0.5;
        const smoothedCommand = clampChargeCommand(targetCharge);
        return emitCommand({
            command: smoothedCommand,
            targetCharge,
            theoreticalSurplus: effectiveSolarPower - calculatedDemand,
            statusFill: "yellow",
            statusText: `Cmd: ${Math.round(smoothedCommand)}W | Rule: ${ruleApplied} | Grid: stale`
        });
    }

    const holdCommand = Math.round(Math.max(lastCommand, currentSetInflow, batteryInflow, 0));
    node.status({
        fill: "green",
        shape: "ring",
        text: `Stable @ ${holdCommand}W`
    });
    return null;
}

function clampChargeCommand(value) {
    let clampedValue = value;

    if (clampedValue > maxInverterPower) {
        clampedValue = maxInverterPower;
        clampReason = "Inverter Max";
    }
    if (clampedValue > maxChargePower) {
        clampedValue = maxChargePower;
        clampReason = "Battery Max";
    }
    if (clampedValue < 0) {
        clampedValue = 0;
        ruleApplied = "Floor (0W)";
    }

    return clampedValue;
}

function appendRule(ruleName) {
    ruleApplied = ruleApplied === "None" ? ruleName : `${ruleApplied} + ${ruleName}`;
}

function limitUnstableSolarSlew(command) {
    if (!solarIsUnstable) {
        return command;
    }

    const activeReference = Math.max(lastCommand, currentSetInflow, batteryInflow, 0);
    if (activeReference <= 0) {
        return command;
    }

    const maxIncrease = activeReference + unstableSolarMaxIncreaseW;
    const maxDecrease =
        gridPower > unstableSolarEmergencyImportW
            ? 0
            : Math.max(0, activeReference - unstableSolarMaxDecreaseW);
    const limitedCommand = Math.min(maxIncrease, Math.max(maxDecrease, command));

    if (Math.round(limitedCommand) !== Math.round(command)) {
        appendRule("Solar-Unstable Slew Limit");
    }

    return limitedCommand;
}

function limitLowSocMildImportDrop(command) {
    const activeReference = Math.max(lastCommand, currentSetInflow, batteryInflow, 0);
    const theoreticalSurplus = effectiveSolarPower - calculatedDemand;
    const hasPositiveSurplus = theoreticalSurplus > targetBuffer;
    const lowSocImportShouldBeTreatedGently =
        gridPower <= lowSocMildImportThresholdW ||
        (hasPositiveSurplus && gridPower <= lowSocPositiveSurplusImportThresholdW);
    const stepDownFloor = Math.max(0, activeReference - lowSocMaxDecreaseW);
    const positiveSurplusFloor = hasPositiveSurplus
        ? Math.min(activeReference, theoreticalSurplus * 0.5)
        : 0;
    const commandFloor = Math.max(stepDownFloor, positiveSurplusFloor);
    const shouldLimitDrop =
        soc <= minSoc + lowSocReserveMargin &&
        activeReference > 0 &&
        gridPower >= 0 &&
        lowSocImportShouldBeTreatedGently &&
        command < commandFloor;

    if (!shouldLimitDrop) {
        return command;
    }

    appendRule("Low-SoC Mild-Import Slew Limit");
    return commandFloor;
}

function limitChargeSlew(command) {
    return limitLowSocMildImportDrop(limitUnstableSolarSlew(command));
}

function emitCommand({ command, targetCharge, theoreticalSurplus, statusFill, statusText }) {
    const roundedCommand = Math.round(command);
    const roundedTarget = Math.round(targetCharge);
    const roundedSurplus = Math.round(theoreticalSurplus);
    const delta = Math.abs(command - lastCommand);

    msg.derived = msg.derived || {};
    msg.derived.solar = msg.derived.solar || {};
    msg.derived.energy = msg.derived.energy || {};
    msg.derived.solar.effectivePower = Math.round(effectiveSolarPower);
    msg.derived.energy.theoreticalSurplus = roundedSurplus;
    msg.action = msg.action || {};
    msg.action.charge = msg.action.charge || {};
    msg.action.charge.targetPower = roundedTarget;
    msg.action.charge.commandPower = roundedCommand;
    msg.action.charge.ruleApplied = ruleApplied;
    msg.action.charge.clampReason = clampReason;
    context.set("lastCommand", command);
    context.set("lastGridPower", gridPower);
    context.set("lastSolarSecondaryPower", solarSecondaryPower);
    context.set(
        "lastDemandEstimate",
        getFirstFinite([demandTiming?.currentEstimate, msg.derived?.demand?.current], 0)
    );

    const insights = {
        payload: {
            timestamp: new Date().toISOString(),
            efficiency: {
                gridExport: gridPower < 0 ? Math.abs(gridPower) : 0,
                isLeaking: isExporting
            },
            calculation: {
                theoreticalSurplus: roundedSurplus,
                targetCharge: roundedTarget,
                finalCommand: roundedCommand
            },
            constraints: {
                clamp: clampReason,
                rule: ruleApplied,
                delta: Math.round(delta)
            },
            sensors: {
                solarLive: liveSolarPower,
                solarStable: stableSolarPower,
                solarEffective: Math.round(effectiveSolarPower),
                demand: calculatedDemand,
                grid: gridPower,
                soc: soc
            }
        }
    };

    node.status({
        fill: statusFill,
        shape: "dot",
        text: statusText
    });

    return [msg, insights];
}

if (!demandSnapshotReliable) {
    ruleApplied = "Low-Confidence Grid Steering";

    const baseCommand = Math.max(lastCommand, currentSetInflow, 0);
    const currentDemandEstimate = getFirstFinite(
        [demandTiming?.currentEstimate, msg.derived?.demand?.current],
        0
    );
    const demandDelta = Number.isFinite(lastDemandEstimate)
        ? currentDemandEstimate - lastDemandEstimate
        : null;
    let targetCharge = baseCommand;

    if (isExporting) {
        const exportCorrection = Math.abs(gridPower) + targetBuffer;
        const commandAlreadyAheadOfMeasuredInflow = currentSetInflow > batteryInflow + targetBuffer;

        if (commandAlreadyAheadOfMeasuredInflow && Math.abs(gridPower) <= targetBuffer) {
            targetCharge = baseCommand;
        } else if (maxChargePower > 800 || Math.abs(gridPower) <= targetBuffer * 2) {
            targetCharge = baseCommand + exportCorrection;
        }
    } else if (gridPower > targetBuffer) {
        const importCorrection = gridPower - targetBuffer;
        const demandSpike = currentDemandEstimate - calculatedDemand;
        const isShortDemandPeak =
            demandDelta !== null &&
            demandDelta > 0 &&
            demandSpike > 100 &&
            calculatedDemand <= lastDemandEstimate + targetBuffer &&
            gridPower <= targetBuffer * 2;
        if (isShortDemandPeak) {
            targetCharge = baseCommand;
        } else {
            const demandCorrection =
                demandDelta !== null && demandDelta > 0 ? demandDelta * 2 : importCorrection;

            targetCharge = baseCommand - Math.max(importCorrection, demandCorrection);
        }
    }

    const smoothedCommand = clampChargeCommand(limitChargeSlew(targetCharge));
    return emitCommand({
        command: smoothedCommand,
        targetCharge,
        theoreticalSurplus: effectiveSolarPower - calculatedDemand,
        statusFill: isExporting ? "yellow" : "green",
        statusText: `Cmd: ${Math.round(smoothedCommand)}W | Rule: ${ruleApplied} | Grid: ${Math.round(
            gridPower
        )}W`
    });
}

// 3. THE CALCULATION (Grid-Anchor)
const theoreticalSurplus = effectiveSolarPower - calculatedDemand;
let targetCharge = Math.max(0, theoreticalSurplus + targetBuffer);

// If we are exporting, add an explicit anti-export correction on top of the
// stable surplus target so slight leaks are not ignored.
if (isExporting) {
    const exportIntensity = Math.abs(gridPower);
    const exportBoost = Math.round(exportIntensity * exportBoostFactor);
    targetCharge = Math.max(targetCharge, currentSetInflow + exportBoost);
    ruleApplied = "Anti-Export";
}

// 4. SANITY CHECKS & SUSTAIN
// If solar production is > 150W, we keep the charging circuit 'warm' at 50W,
// even if the house is currently importing from the grid.
const productionThreshold = 150; // Adjust this based on your 'sunny enough' preference

if (totalProduced > productionThreshold && targetCharge < minSustain) {
    targetCharge = minSustain;
    ruleApplied = "Sustain (Production)";
    // If we are sustained at 50W, but we are still exporting, nudge the charge
    // above sustain to swallow the leak.
    if (isExporting) {
        targetCharge = Math.max(targetCharge, minSustain + Math.abs(gridPower));
        ruleApplied = "Sustain + Anti-Leak";
    }
}

// Keep the Solar Ceiling safety
const solarCeiling = theoreticalSurplus + 100;
if (targetCharge > solarCeiling && !isExporting) {
    // But we don't want to charge from the grid!
    // If targetCharge is Sustain(50) but theoreticalSurplus is -58,
    // we need to decide if we 'waste' 50W of grid power to keep the battery warm.
    // Let's allow it ONLY if the deficit isn't massive.
    if (theoreticalSurplus < -200) {
        targetCharge = 0; // House is too hungry, give up on sustain.
    }
}

// Minimum Sustain: If sun is out, stay at 50W even if demand is high
if (theoreticalSurplus > 10 && targetCharge < minSustain) {
    targetCharge = minSustain;
}

// Hard floor
if (targetCharge < 0) targetCharge = 0;

const chargingWasActive = Math.max(lastCommand, currentSetInflow, batteryInflow) > 0;
const solarSwitchGuardFloor = totalProduced * solarSwitchGuardFactor;
if (
    chargingWasActive &&
    totalProduced > productionThreshold &&
    targetCharge < solarSwitchGuardFloor
) {
    targetCharge = solarSwitchGuardFloor;
    ruleApplied = "Solar Floor (Switch Guard)";
}

// 5. DYNAMIC SMOOTHING (Slew Rate)
// Instead of a fixed Alpha, we use a "Fast-Up, Slow-Down" approach.
let finalAlpha;
if (isExporting) {
    // CRITICAL: If we are exporting, we jump to the target IMMEDIATELY
    finalAlpha = 1.0;
} else if (targetCharge > lastCommand) {
    // If we are increasing charge (but not leaking), move fast
    finalAlpha = 0.9;
} else {
    // If we are decreasing charge, move slowly to stay "warm"
    finalAlpha = 0.2;
}
let smoothedCommand = targetCharge * finalAlpha + lastCommand * (1 - finalAlpha);

// Rule: Minimum SoC Recovery
if (soc <= minSoc && totalProduced >= 150) {
    const recoveryCharge = totalProduced / 2;
    if (smoothedCommand < recoveryCharge) {
        smoothedCommand = recoveryCharge;
        ruleApplied = "SoC Recovery";
    }
}

if (
    chargingWasActive &&
    totalProduced > productionThreshold &&
    smoothedCommand < solarSwitchGuardFloor
) {
    smoothedCommand = solarSwitchGuardFloor;
    ruleApplied = "Solar Floor (Switch Guard)";
}

smoothedCommand = clampChargeCommand(limitChargeSlew(smoothedCommand));

// 7. CYCLE GUARD (Deadband)
// If we are stable and not exporting, don't update if change is tiny
const delta = Math.abs(smoothedCommand - lastCommand);
if (delta < 5 && gridPower >= 0 && batteryInflow === 0) {
    node.status({ fill: "green", shape: "ring", text: `Stable @ ${Math.round(smoothedCommand)}W` });
    return null;
}

// 8. OUTPUTS & PERSISTENCE
return emitCommand({
    command: smoothedCommand,
    targetCharge,
    theoreticalSurplus,
    statusFill: isExporting ? "red" : "green",
    statusText: `Cmd: ${Math.round(smoothedCommand)}W | Clamp: ${clampReason} | Export: ${Math.round(
        gridPower
    )}W`
});

function getFirstFinite(values, fallback = 0) {
    for (const value of values) {
        if (Number.isFinite(value)) {
            return value;
        }
    }

    return fallback;
}

const data = msg.data || {};
const derived = msg.derived || {};

const sunAbove = data.sun?.aboveHorizon === true;
const soc = getFirstFinite([data.battery?.soc], 0);
const minimalCharge = getFirstFinite([data.battery?.minSoc], 0);
const maxSoc = getFirstFinite([data.battery?.socLimit], 100);
const totalSolarRemaining = getFirstFinite([data.forecast?.solarRemainingWh], 0);
const nextHourSolar = getFirstFinite([data.forecast?.nextHourWh], 0);
const solarPower = getFirstFinite([derived.solar?.livePower], 0);
const demandPower = getFirstFinite([derived.demand?.defensiveTarget, derived.demand?.current], 0);
const localHour = new Date().getHours();

let toCharge = null;
let toDischarge = null;

/**
 * DECISION LOGIC:
 * Switch to NIGHT/DISCHARGE mode only if:
 * - Sun is down OR the total remaining forecast is negligible (< 50Wh)
 * - AND we aren't in a "Low Battery" state where we should strictly wait for sun.
 */
const batteryHasReserve = soc > minimalCharge;
const batteryHasMorningReserve = soc >= minimalCharge + 30;
const batteryNearMaxReserve = soc >= maxSoc - 20;
const lowSocWithoutUsableNearTermSolar = !batteryHasReserve && nextHourSolar < 50;
const isSolarDayOver = !sunAbove || totalSolarRemaining < 50 || lowSocWithoutUsableNearTermSolar;
const nightLowSocBlock = isSolarDayOver && !batteryHasReserve;
const weakMorningSolar =
    sunAbove &&
    localHour < 12 &&
    batteryHasMorningReserve &&
    solarPower > 50 &&
    solarPower < demandPower;
const eveningSolarDrop =
    sunAbove &&
    localHour >= 17 &&
    batteryNearMaxReserve &&
    solarPower > 0 &&
    solarPower < demandPower;

msg.action = msg.action || {};
msg.action.decision = {
    isSolarDayOver,
    batteryHasReserve,
    nightLowSocBlock,
    dischargeStopThreshold: minimalCharge
};
msg.action.battery = msg.action.battery || {};
msg.action.battery.discharge = msg.action.battery.discharge || {};
msg.action.battery.discharge.stopRequested = nightLowSocBlock;
msg.action.battery.discharge.blockedByLowSoc = nightLowSocBlock;

if (nightLowSocBlock) {
    node.status({
        fill: "red",
        shape: "dot",
        text: `Empty Battery, no solar power: ${solarPower}W, solar forecast ${totalSolarRemaining}Wh, battery soc: ${soc}`
    });
} else if (isSolarDayOver && batteryHasReserve) {
    toDischarge = msg;
    node.status({
        fill: "blue",
        shape: "dot",
        text: `Discharge - Night, remaing solar ${totalSolarRemaining}Wh, Solar Day is Over: ${isSolarDayOver}, battery has res: ${batteryHasReserve}`
    });
} else if (weakMorningSolar) {
    toDischarge = msg;
    node.status({
        fill: "blue",
        shape: "dot",
        text: `Discharge - Weak morning solar, solar ${solarPower}W, demand ${demandPower}W, battery soc: ${soc}`
    });
} else if (eveningSolarDrop) {
    toDischarge = msg;
    node.status({
        fill: "blue",
        shape: "dot",
        text: `Discharge - Evening solar drop, solar ${solarPower}W, demand ${demandPower}W, battery soc: ${soc}`
    });
} else if (solarPower > 0) {
    toCharge = msg;
    node.status({
        fill: "yellow",
        shape: "dot",
        text: `Charge - Day/Solar: remaing solar ${totalSolarRemaining}Wh`
    });
} else {
    node.status({
        fill: "red",
        shape: "dot",
        text: `Empty Battery, no solar power: ${solarPower}W, solar forecast ${totalSolarRemaining}Wh, battery soc: ${soc}`
    });
}

return [toCharge, toDischarge];

function getFirstFinite(values, fallback = 0) {
    for (const value of values) {
        if (Number.isFinite(value)) {
            return value;
        }
    }

    return fallback;
}

const data = msg.data || {};
const chargeAction = msg.action?.charge || {};

const soc = getFirstFinite([data.battery?.soc], 0);
const maxSoc = getFirstFinite([data.battery?.socLimit], 100);
const currentSetInflow = getFirstFinite([data.battery?.chargeSetpoint], 0);
const maxChargeHardware = getFirstFinite(
    [data.battery?.chargeHardwareMaxPower, data.battery?.chargeMaxPower],
    800
);
const gridPower = getFirstFinite([data.grid?.power], 0);
const gridExport = Math.max(0, -gridPower);

let targetCharge = Math.abs(getFirstFinite([chargeAction.commandPower], 0));
let reason = "Adjusting normally";

if (soc + 1.1 > maxSoc) {
    targetCharge = 0;
    reason = "BATTERY_FULL_OVERFLOW";
} else if (targetCharge > maxChargeHardware) {
    reason = "MAX_CHARGE_OVERFLOW";
}

targetCharge = Math.max(0, Math.min(maxChargeHardware, targetCharge));

const logMsg = {
    payload: {
        time: new Date().toLocaleString("de-DE"),
        grid: gridPower,
        gridExport,
        soc: soc,
        targetCharge: Math.round(targetCharge),
        reason: reason
    }
};

let hardwareCmd = null;
if (Math.abs(targetCharge - currentSetInflow) > 10) {
    hardwareCmd = { payload: Math.round(targetCharge) };
} else {
    reason = "No change - no need to adjust";
}

const sequencerTrigger = {
    payload: reason,
    gridExport
};

node.status({ fill: "green", shape: "dot", text: `${Math.round(targetCharge)}W (${reason})` });

return [hardwareCmd, sequencerTrigger, logMsg];

// 1. DATA FROM PREVIOUS NODES
const action = msg.payload;
const exportPower = msg.gridExport || 0; // The extra W we can't store
const now = Date.now();

// 2. STATE PERSISTENCE (Track status of loads)
let loads = context.get("loads") || {
    dryer: { active: false, lastChange: 0, power: 250, entity: "switch.dryer" },
    dehumidifier: { active: false, lastChange: 0, power: 150, entity: "switch.dehumidifier" }
};

// 3. MINIMUM RUN TIME (Safety: 15 minutes)
const minRunTime = 15 * 60 * 1000;

// 4. LOGIC: ADDING LOADS (Turn ON)
if (action.includes("OVERFLOW")) {
    // Try to turn on the first available load in order of priority
    if (!loads.dehumidifier.active && exportPower > loads.dehumidifier.power + 50) {
        loads.dehumidifier.active = true;
        loads.dehumidifier.lastChange = now;
        node.send({ payload: "ON", topic: loads.dehumidifier.entity });
    } else if (!loads.dryer.active && exportPower > loads.dryer.power + 100) {
        loads.dryer.active = true;
        loads.dryer.lastChange = now;
        node.send({ payload: "ON", topic: loads.dryer.entity });
    }
}

// 5. LOGIC: REMOVING LOADS (Turn OFF)
// If we are back to NORMAL (importing or zero), check if we need to shed load
if (action === "NORMAL" || exportPower < 20) {
    // Turn off in reverse order, but only if they've run long enough
    if (loads.dryer.active && now - loads.dryer.lastChange > minRunTime) {
        loads.dryer.active = false;
        node.send({ payload: "OFF", topic: loads.dryer.entity });
    } else if (loads.dehumidifier.active && now - loads.dehumidifier.lastChange > minRunTime) {
        loads.dehumidifier.active = false;
        node.send({ payload: "OFF", topic: loads.dehumidifier.entity });
    }
}

context.set("loads", loads);
node.status({
    fill: loads.dryer.active ? "green" : "grey",
    shape: "dot",
    text: `Dryer: ${loads.dryer.active} | Dehum: ${loads.dehumidifier.active}`
});

function hasMessageValue(root, path) {
    let current = root;
    for (const segment of path.split(".")) {
        if (
            current === null ||
            current === undefined ||
            !Object.prototype.hasOwnProperty.call(current, segment)
        ) {
            return false;
        }
        current = current[segment];
    }
    return current !== undefined;
}

function abortForMissing(requiredPaths) {
    const missing = requiredPaths.filter((path) => !hasMessageValue(msg, path));
    if (missing.length === 0) {
        return false;
    }

    const errorMessage = `Missing mandatory message fields: ${missing.join(", ")}`;
    node.status({ fill: "red", shape: "ring", text: `Missing data: ${missing.join(", ")}` });
    node.error(errorMessage, msg);
    return true;
}

if (
    abortForMissing([
        "data.battery.dischargeSetpoint",
        "data.forecast.nextHourWh",
        "action.battery.discharge.commandPower"
    ])
) {
    return null;
}

const data = msg.data;
const action = msg.action;

const currentSetLimit = data.battery.dischargeSetpoint;

// 1. CHOOSE THE TARGET
// We want to reach the 'forcedRate' (to empty the battery),
// OR follow the 'defensiveTarget' (5-min average) if the house is active.
let targetDischarge = action.battery.discharge.commandPower;
const nextHourWh = data.forecast.nextHourWh;

// 2. HARDWARE OUTPUT
let hardwareCmd = null;
if (Math.abs(targetDischarge - currentSetLimit) > 5) {
    hardwareCmd = { payload: Math.round(targetDischarge) };
}

node.status({
    fill: "blue",
    shape: nextHourWh > 50 ? "ring" : "dot",
    text: `target: ${Math.round(targetDischarge)}W`
});

return [hardwareCmd];

// Specification:
// Encapsulate Home Assistant entity ids in one place and expose a semantic,
// reusable internal message structure for all subsequent controller nodes.
const ha = msg.payload || {};
const now = Date.now();
const triggerIntervalSeconds =
    msg.meta?.trigger?.intervalSeconds || flow.get("triggerIntervalSeconds") || 20;
const retainedReadingMs = Math.max(60 * 1000, triggerIntervalSeconds * 6 * 1000);
const configuredMinimumHouseDemandW = parseFloat(flow.get("minimumHouseDemandW"));
const minimumHouseDemandW = Number.isFinite(configuredMinimumHouseDemandW)
    ? configuredMinimumHouseDemandW
    : 40;
const plausibilityThresholds = {
    maxSensorAgeMs: Math.max(20 * 1000, triggerIntervalSeconds * 2 * 1000),
    maxSensorSpreadMs: Math.max(20 * 1000, triggerIntervalSeconds * 2 * 1000),
    minimumHouseDemandW: minimumHouseDemandW,
    setpointToleranceW: Math.max(40, minimumHouseDemandW)
};
let lastValidNumbers = context.get("lastValidNumbers") || {};

function getEntity(entityId) {
    return ha[entityId];
}

function getEntityTimeInfo(entity) {
    const candidates = [
        ["last_reported", entity?.last_reported],
        ["last_updated", entity?.last_updated],
        ["last_changed", entity?.last_changed],
        ["attributes.last_reported", entity?.attributes?.last_reported],
        ["attributes.last_updated", entity?.attributes?.last_updated],
        ["attributes.last_changed", entity?.attributes?.last_changed]
    ];

    for (const [source, rawTimestamp] of candidates) {
        if (!rawTimestamp) {
            continue;
        }

        const timestampMs = new Date(rawTimestamp).getTime();
        if (Number.isFinite(timestampMs)) {
            return {
                timestamp: String(rawTimestamp),
                timestampMs,
                ageMs: Math.max(0, now - timestampMs),
                source
            };
        }
    }

    return {
        timestamp: null,
        timestampMs: null,
        ageMs: null,
        source: null
    };
}

function readNumber(entityId, fallback = 0, options = {}) {
    const { remember = false, maxAgeMs = retainedReadingMs } = options;
    const entity = getEntity(entityId);
    const rawState = entity?.state ?? null;
    const parsedValue = parseFloat(rawState);
    const isValid = Number.isFinite(parsedValue);
    const timeInfo = getEntityTimeInfo(entity);
    let value = fallback;
    let usedLastValid = false;
    let lastValidAgeMs = null;

    if (isValid) {
        value = parsedValue;
        if (remember) {
            lastValidNumbers[entityId] = {
                value: parsedValue,
                timestamp: now
            };
        }
    } else if (remember) {
        const cached = lastValidNumbers[entityId];
        if (cached) {
            lastValidAgeMs = now - cached.timestamp;
            if (lastValidAgeMs <= maxAgeMs) {
                value = cached.value;
                usedLastValid = true;
            }
        }
    }

    return {
        entityId,
        rawState,
        parsedValue: isValid ? parsedValue : null,
        value,
        isValid,
        sourceTimestamp: timeInfo.timestamp,
        sourceTimestampMs: timeInfo.timestampMs,
        sourceAgeMs: timeInfo.ageMs,
        sourceTimestampField: timeInfo.source,
        usedLastValid,
        usedFallback: !isValid && !usedLastValid,
        lastValidAgeMs
    };
}

function getNumber(entityId, fallback = 0, options = {}) {
    return readNumber(entityId, fallback, options).value;
}

function getString(entityId, fallback = "") {
    const value = getEntity(entityId)?.state;
    return value !== undefined && value !== null ? String(value) : fallback;
}

function readWh(entityId, fallback = 0, options = {}) {
    const { remember = false, maxAgeMs = retainedReadingMs } = options;
    const entity = getEntity(entityId);
    const rawState = entity?.state ?? null;
    const parsedValue = parseFloat(rawState);
    const isValid = Number.isFinite(parsedValue);
    const timeInfo = getEntityTimeInfo(entity);
    const unit = entity?.attributes?.unit_of_measurement;
    let value = fallback;
    let usedLastValid = false;
    let lastValidAgeMs = null;

    if (isValid) {
        value = unit === "kWh" ? parsedValue * 1000 : parsedValue;
        if (remember) {
            lastValidNumbers[entityId] = {
                value,
                timestamp: now
            };
        }
    } else if (remember) {
        const cached = lastValidNumbers[entityId];
        if (cached) {
            lastValidAgeMs = now - cached.timestamp;
            if (lastValidAgeMs <= maxAgeMs) {
                value = cached.value;
                usedLastValid = true;
            }
        }
    }

    return {
        entityId,
        rawState,
        parsedValue: isValid ? value : null,
        value,
        isValid,
        sourceTimestamp: timeInfo.timestamp,
        sourceTimestampMs: timeInfo.timestampMs,
        sourceAgeMs: timeInfo.ageMs,
        sourceTimestampField: timeInfo.source,
        usedLastValid,
        usedFallback: !isValid && !usedLastValid,
        lastValidAgeMs
    };
}

function summarizeReading(reading) {
    return {
        entityId: reading.entityId,
        rawState: reading.rawState,
        parsedValue: reading.parsedValue,
        value: reading.value,
        isValid: reading.isValid,
        sourceTimestamp: reading.sourceTimestamp,
        sourceTimestampMs: reading.sourceTimestampMs,
        sourceAgeMs: reading.sourceAgeMs,
        sourceTimestampField: reading.sourceTimestampField,
        isStale: reading.isStale,
        staleAgeThresholdMs: reading.staleAgeThresholdMs,
        usedLastValid: reading.usedLastValid,
        usedFallback: reading.usedFallback,
        lastValidAgeMs: reading.lastValidAgeMs
    };
}

function addStaleness(reading) {
    return {
        ...reading,
        isStale:
            reading.isValid &&
            Number.isFinite(reading.sourceAgeMs) &&
            reading.sourceAgeMs >= plausibilityThresholds.maxSensorAgeMs,
        staleAgeThresholdMs: plausibilityThresholds.maxSensorAgeMs
    };
}

function buildAgeStats(readings) {
    const ages = readings.map((reading) => reading.sourceAgeMs).filter(Number.isFinite);
    if (ages.length === 0) {
        return {
            minAgeMs: null,
            maxAgeMs: null,
            spreadMs: null
        };
    }

    const minAgeMs = Math.min(...ages);
    const maxAgeMs = Math.max(...ages);

    return {
        minAgeMs,
        maxAgeMs,
        spreadMs: maxAgeMs - minAgeMs
    };
}

const gridPowerReading = addStaleness(
    readNumber("sensor.smartmeter_keller_sml_watt_summe", 0, {
        remember: true
    })
);
const solarPrimaryPowerReading = addStaleness(
    readNumber("sensor.wechselrichter_ac_leistung", 0, {
        remember: true
    })
);
const solarSecondaryPowerReading = addStaleness(
    readNumber("sensor.hoymiles600_power", 0, {
        remember: true
    })
);
const batteryChargePowerReading = addStaleness(
    readNumber("sensor.solarflow_800_pro_grid_input_power", 0, {
        remember: true
    })
);
const batteryDischargePowerReading = addStaleness(
    readNumber("sensor.solarflow_800_pro_output_home_power", 0, {
        remember: true
    })
);

const demandComponentReadings = [
    { key: "grid", label: "gridPower", reading: gridPowerReading, sign: 1 },
    {
        key: "batteryDischarge",
        label: "batteryDischargePower",
        reading: batteryDischargePowerReading,
        sign: 1
    },
    { key: "solarPrimary", label: "solarPrimaryPower", reading: solarPrimaryPowerReading, sign: 1 },
    {
        key: "solarSecondary",
        label: "solarSecondaryPower",
        reading: solarSecondaryPowerReading,
        sign: 1
    },
    {
        key: "batteryCharge",
        label: "batteryChargePower",
        reading: batteryChargePowerReading,
        sign: -1
    }
];

const demandPowerRaw = demandComponentReadings.reduce(
    (sum, component) => sum + component.reading.value * component.sign,
    0
);
const demandPowerZeroFallback = demandComponentReadings.reduce((sum, component) => {
    const readingValue = component.reading.isValid ? component.reading.parsedValue : 0;
    return sum + readingValue * component.sign;
}, 0);
const demandInvalidInputs = demandComponentReadings
    .filter((component) => !component.reading.isValid)
    .map((component) => component.label);
const sunAboveHorizon = getString("sun.sun") === "above_horizon";
const sunNextRising = getEntity("sun.sun")?.attributes?.next_rising || null;
const demandPlausibilityComponents = demandComponentReadings.filter((component) => {
    const isIdleNightSolar =
        !sunAboveHorizon &&
        (component.key === "solarPrimary" || component.key === "solarSecondary") &&
        component.reading.value === 0;

    return !isIdleNightSolar;
});
const demandRetainedInputs = demandComponentReadings
    .filter((component) => component.reading.usedLastValid)
    .map((component) => component.label);
const demandStaleInputs = demandPlausibilityComponents
    .filter((component) => component.reading.isStale)
    .map((component) => component.label);
const demandAgeStats = buildAgeStats(
    demandPlausibilityComponents.map((component) => component.reading)
