        batteryChargeUsedLastValid: batteryChargePowerReading.usedLastValid,
        batteryChargeLastValidAgeMs: batteryChargePowerReading.lastValidAgeMs,
        batteryDischargeState: batteryDischargePowerReading.rawState,
        batteryDischargeParsedPower: batteryDischargePowerReading.parsedValue,
        batteryDischargePower: batteryDischargePowerReading.value,
        batteryDischargeTimestamp: batteryDischargePowerReading.sourceTimestamp,
        batteryDischargeAgeMs: batteryDischargePowerReading.sourceAgeMs,
        batteryDischargeValid: batteryDischargePowerReading.isValid,
        batteryDischargeStale: batteryDischargePowerReading.isStale,
        batteryDischargeUsedLastValid: batteryDischargePowerReading.usedLastValid,
        batteryDischargeLastValidAgeMs: batteryDischargePowerReading.lastValidAgeMs,
        totalSolarPower: msg.data.solar.totalPower,
        demandPowerRaw: Math.round(demandPowerRaw),
        demandPower: Math.round(demandPower),
        demandPowerZeroFallback: Math.round(demandPowerZeroFallback),
        demandPowerClamped: demandPowerClamped,
        demandWouldBeNegativeWithZeroFallback: demandPowerZeroFallback < 0,
        demandPlausible: demandPlausibility.isConsistent,
        demandPlausibilityIssues: demandPlausibilityIssues.join("|"),
        demandPlausibilityDetails: demandPlausibilityDetails.join("|"),
        demandStaleInputs: demandStaleInputs.join("|"),
        demandInputAgeSpreadMs: demandAgeStats.spreadMs,
        demandMaxInputAgeMs: demandAgeStats.maxAgeMs,
        demandBelowMinimumExpected: demandBelowMinimumExpected,
        demandMinimumExpectedPower: plausibilityThresholds.minimumHouseDemandW,
        demandChargeSetpointMismatch: chargeSetpointMismatch,
        demandDischargeSetpointMismatch: dischargeSetpointMismatch,
        demandInvalidInputs: demandInvalidInputs.join("|"),
        demandRetainedInputs: demandRetainedInputs.join("|")
    }
};

if (demandInvalidInputs.length > 0 || demandPowerClamped || !demandPlausibility.isConsistent) {
    const statusDetails =
        demandInvalidInputs.length > 0
            ? `invalid ${demandInvalidInputs.join(",")}`
            : demandPlausibilityDetails[0] || "negative demand clamped";
    node.status({
        fill: "yellow",
        shape: "ring",
        text: `Demand ${Math.round(demandPower)}W | ${statusDetails}`
    });
} else {
    node.status({
        fill: "green",
        shape: "dot",
        text: `Demand ${Math.round(demandPower)}W`
    });
}

return [msg, telemetry];

// 1. Calculate current real house demand
const map = msg.payload || {};
const now = Date.now();

if (!msg.meta) {
    msg.meta = {};
}
if (!msg.derived) {
    msg.derived = {};
}
msg.derived.demand = msg.derived.demand || {};
msg.derived.solar = msg.derived.solar || {};

function getEntity(entityId) {
    return map[entityId];
}

function getEntityTimeInfo(entity) {
    const candidates = [
        ["last_reported", entity?.last_reported],
        ["last_updated", entity?.last_updated],
        ["last_changed", entity?.last_changed],
        ["attributes.last_reported", entity?.attributes?.last_reported],
        ["attributes.last_updated", entity?.attributes?.last_updated],
        ["attributes.last_changed", entity?.attributes?.last_changed]
    ];

    for (const [source, rawTimestamp] of candidates) {
        if (!rawTimestamp) {
            continue;
        }

        const timestampMs = new Date(rawTimestamp).getTime();
        if (Number.isFinite(timestampMs)) {
            return {
                timestamp: String(rawTimestamp),
                timestampMs,
                ageMs: Math.max(0, now - timestampMs),
                source
            };
        }
    }

    return {
        timestamp: null,
        timestampMs: null,
        ageMs: null,
        source: null
    };
}

function readSensor(entityId) {
    const entity = getEntity(entityId);
    const parsedValue = parseFloat(entity?.state);
    const timeInfo = getEntityTimeInfo(entity);

    return {
        entityId,
        rawState: entity?.state ?? null,
        value: Number.isFinite(parsedValue) ? parsedValue : 0,
        isValid: Number.isFinite(parsedValue),
        timestamp: timeInfo.timestamp,
        timestampMs: timeInfo.timestampMs,
        ageMs: timeInfo.ageMs,
        timestampSource: timeInfo.source
    };
}

function readingFromNormalization(key, entityId) {
    const reading = msg.meta?.normalization?.readings?.[key];
    if (!reading) {
        return null;
    }

    return {
        entityId,
        rawState: reading.rawState ?? null,
        value: Number.isFinite(reading.value) ? reading.value : 0,
        isValid: reading.isValid !== false && Number.isFinite(reading.value),
        timestamp: reading.sourceTimestamp ?? null,
        timestampMs: reading.sourceTimestampMs ?? null,
        ageMs: reading.sourceAgeMs ?? null,
        timestampSource: reading.sourceTimestampField ?? null,
        isStale: reading.isStale === true,
        usedLastValid: reading.usedLastValid === true,
        usedFallback: reading.usedFallback === true
    };
}

function readInput(key, entityId) {
    return readingFromNormalization(key, entityId) || readSensor(entityId);
}

function readString(entityId, fallback = "") {
    const value = getEntity(entityId)?.state;
    return value !== undefined && value !== null ? String(value) : fallback;
}

function buildAgeStats(readings) {
    const ages = readings.map((reading) => reading.ageMs).filter(Number.isFinite);
    if (ages.length === 0) {
        return {
            minAgeMs: null,
            maxAgeMs: null,
            spreadMs: null,
            averageAgeMs: null
        };
    }

    const minAgeMs = Math.min(...ages);
    const maxAgeMs = Math.max(...ages);
    const totalAgeMs = ages.reduce((sum, ageMs) => sum + ageMs, 0);

    return {
        minAgeMs,
        maxAgeMs,
        spreadMs: maxAgeMs - minAgeMs,
        averageAgeMs: totalAgeMs / ages.length
    };
}

function hasActivePower(reading, threshold = 5) {
    return Math.abs(reading.value) > threshold;
}

function buildDemandTimingReadings({
    grid,
    batteryDischarge,
    solarPrimary,
    solarSecondary,
    batteryCharge,
    sunAboveHorizon
}) {
    return [
        grid,
        ...(hasActivePower(batteryDischarge) ? [batteryDischarge] : []),
        ...(sunAboveHorizon || hasActivePower(solarPrimary) ? [solarPrimary] : []),
        ...(sunAboveHorizon || hasActivePower(solarSecondary) ? [solarSecondary] : []),
        ...(hasActivePower(batteryCharge) ? [batteryCharge] : [])
    ];
}

function clamp01(value) {
    return Math.max(0, Math.min(1, value));
}

function calculateConfidence(ageStats, thresholds, forceZero = false) {
    if (forceZero) {
        return 0;
    }

    const ageConfidence =
        ageStats.maxAgeMs === null ? 1 : clamp01(1 - ageStats.maxAgeMs / thresholds.maxSensorAgeMs);
    const spreadConfidence =
        ageStats.spreadMs === null
            ? 1
            : clamp01(1 - ageStats.spreadMs / thresholds.maxSensorSpreadMs);

    return Math.min(ageConfidence, spreadConfidence);
}

function blendWithFallback(liveValue, fallbackValue, confidence) {
    return liveValue * confidence + fallbackValue * (1 - confidence);
}

function average(values) {
    return values.reduce((sum, value) => sum + value, 0) / Math.max(1, values.length);
}

function standardDeviation(values) {
    if (values.length === 0) {
        return 0;
    }

    const mean = average(values);
    const variance = average(values.map((value) => (value - mean) ** 2));
    return Math.sqrt(variance);
}

function percentile(sortedValues, ratio) {
    if (sortedValues.length === 0) {
        return 0;
    }

    const index = Math.min(
        sortedValues.length - 1,
        Math.max(0, Math.floor((sortedValues.length - 1) * ratio))
    );
    return sortedValues[index];
}

function calculateTrend(values) {
    if (values.length < 2) {
        return 0;
    }

    return values[values.length - 1] - values[0];
}

function classifyTrend(trend, deadband) {
    if (trend > deadband) {
        return "up";
    }
    if (trend < -deadband) {
        return "down";
    }
    return "flat";
}

function countTrendChanges(values, deadband) {
    let changes = 0;
    let previousDirection = "flat";

    for (let index = 1; index < values.length; index += 1) {
        const direction = classifyTrend(values[index] - values[index - 1], deadband);
        if (
            direction !== "flat" &&
            previousDirection !== "flat" &&
            direction !== previousDirection
        ) {
            changes += 1;
        }
        if (direction !== "flat") {
            previousDirection = direction;
        }
    }

    return changes;
}

const triggerIntervalSeconds =
    msg.meta?.trigger?.intervalSeconds || flow.get("triggerIntervalSeconds") || 20;
const historyWindowSeconds = 5 * 60;
const historySamples = Math.max(15, Math.ceil(historyWindowSeconds / triggerIntervalSeconds));
const timingThresholds = {
    maxSensorAgeMs: Math.max(45 * 1000, triggerIntervalSeconds * 4 * 1000),
    maxSensorSpreadMs: Math.max(25 * 1000, Math.round(triggerIntervalSeconds * 2.5 * 1000)),
    reliableConfidence: 0.7
};

const gridReading = readInput("gridPower", "sensor.smartmeter_keller_sml_watt_summe");
const batteryDischargeReading = readInput(
    "batteryDischargePower",
    "sensor.solarflow_800_pro_output_home_power"
);
const solarPrimaryReading = readInput("solarPrimaryPower", "sensor.wechselrichter_ac_leistung");
const solarSecondaryReading = readInput("solarSecondaryPower", "sensor.hoymiles600_power");
const batteryChargeReading = readInput(
    "batteryChargePower",
    "sensor.solarflow_800_pro_grid_input_power"
);
const sunAboveHorizon = msg.data?.sun?.aboveHorizon ?? readString("sun.sun") === "above_horizon";

const demandTimingReadings = buildDemandTimingReadings({
    grid: gridReading,
    batteryDischarge: batteryDischargeReading,
    solarPrimary: solarPrimaryReading,
    solarSecondary: solarSecondaryReading,
    batteryCharge: batteryChargeReading,
    sunAboveHorizon
});
const solarTimingReadings =
    sunAboveHorizon || hasActivePower(solarPrimaryReading) || hasActivePower(solarSecondaryReading)
        ? [solarPrimaryReading, solarSecondaryReading]
        : [];
const demandAgeStats = buildAgeStats(demandTimingReadings);
const solarAgeStats = buildAgeStats(solarTimingReadings);

const currentDemandRaw =
    gridReading.value +
    batteryDischargeReading.value +
    solarPrimaryReading.value +
    solarSecondaryReading.value -
    batteryChargeReading.value;
const currentSolarRaw = solarPrimaryReading.value + solarSecondaryReading.value;

let lastReliableDemand = context.get("lastReliableDemand");
if (!Number.isFinite(lastReliableDemand)) {
    lastReliableDemand = Math.max(0, currentDemandRaw);
}
let lastReliableSolar = context.get("lastReliableSolar");
if (!Number.isFinite(lastReliableSolar)) {
    lastReliableSolar = Math.max(0, currentSolarRaw);
}

const demandConfidence = calculateConfidence(
    demandAgeStats,
    timingThresholds,
    currentDemandRaw < 0
);
const solarConfidence = calculateConfidence(solarAgeStats, timingThresholds);

const currentDemandEstimate = Math.max(
    0,
    blendWithFallback(Math.max(0, currentDemandRaw), lastReliableDemand, demandConfidence)
);
const currentSolarEstimate = Math.max(
    0,
    blendWithFallback(currentSolarRaw, lastReliableSolar, solarConfidence)
);

if (demandConfidence >= timingThresholds.reliableConfidence && currentDemandRaw >= 0) {
    lastReliableDemand = currentDemandEstimate;
    context.set("lastReliableDemand", lastReliableDemand);
}
if (solarConfidence >= timingThresholds.reliableConfidence) {
    lastReliableSolar = currentSolarEstimate;
    context.set("lastReliableSolar", lastReliableSolar);
}

// 2. Manage 5-minute history based on the configured trigger interval
let history = context.get("demandHistory") || [];
history.push(currentDemandEstimate);
while (history.length > historySamples) history.shift();
context.set("demandHistory", history);

let solarHistory = context.get("solarHistory") || [];
solarHistory.push(currentSolarEstimate);
while (solarHistory.length > historySamples) solarHistory.shift();
context.set("solarHistory", solarHistory);

// 3. Calculate Average
const averageDemand = average(history);
const averageSolar = average(solarHistory);

// 4. Calculate Median (P50)
const sorted = [...history].sort((a, b) => a - b);
const lowMiddle = Math.floor((sorted.length - 1) / 2);
const highMiddle = Math.ceil((sorted.length - 1) / 2);
const medianDemand = (sorted[lowMiddle] + sorted[highMiddle]) / 2;
const demandLowerBound = percentile(sorted, 0.2);

const longTermMinimumWindowSamples = Math.max(
    1,
    Math.ceil((48 * 60 * 60) / triggerIntervalSeconds)
);
let demandLowerBoundHistory = context.get("demandLowerBoundHistory") || [];
demandLowerBoundHistory.push(demandLowerBound);
while (demandLowerBoundHistory.length > longTermMinimumWindowSamples) {
    demandLowerBoundHistory.shift();
}
context.set("demandLowerBoundHistory", demandLowerBoundHistory);
const demandLongTermMinimum = Math.min(...demandLowerBoundHistory);
const demandStdDev = standardDeviation(history);
const solarStdDev = standardDeviation(solarHistory);
const trendWindowSamples = Math.min(
    history.length,
    Math.max(3, Math.ceil(60 / triggerIntervalSeconds))
);
const demandTrendValues = history.slice(-trendWindowSamples);
const solarTrendValues = solarHistory.slice(-trendWindowSamples);
const demandTrend = calculateTrend(demandTrendValues);
const solarTrend = calculateTrend(solarTrendValues);
const stabilityThresholds = {
    demandStdDev: 80,
    solarStdDev: 120,
    demandTrendDeadband: 15,
    solarTrendDeadband: 20,
    unstableTrendChanges: 2
};
const demandTrendDirection = classifyTrend(demandTrend, stabilityThresholds.demandTrendDeadband);
const solarTrendDirection = classifyTrend(solarTrend, stabilityThresholds.solarTrendDeadband);
const demandTrendChanges = countTrendChanges(
    demandTrendValues,
    stabilityThresholds.demandTrendDeadband
);
const solarTrendChanges = countTrendChanges(
    solarTrendValues,
    stabilityThresholds.solarTrendDeadband
);
const demandStability =
    demandStdDev <= stabilityThresholds.demandStdDev &&
    demandTrendChanges < stabilityThresholds.unstableTrendChanges
        ? "stable"
        : "unstable";
const solarStability =
    solarStdDev <= stabilityThresholds.solarStdDev &&
    solarTrendChanges < stabilityThresholds.unstableTrendChanges
        ? "stable"
        : "unstable";
const stabilityMode =
    demandStability === "stable" && solarStability === "stable"
        ? "stable_stable"
        : demandStability === "unstable" && solarStability === "stable"
          ? "demand_unstable"
          : demandStability === "stable" && solarStability === "unstable"
            ? "solar_unstable"
            : "unstable_unstable";

// 5. ASYMMETRIC LOGIC
const defensiveTarget = Math.min(medianDemand, currentDemandEstimate);
const proactiveSolar = currentSolarEstimate;

// 6. THE "CONTINUOUS FLOW" BIAS
const flowBias = proactiveSolar > 50 ? 20 : 0;
const snapshotLagging =
    currentDemandRaw < 0 ||
    (demandAgeStats.spreadMs !== null &&
        demandAgeStats.spreadMs > timingThresholds.maxSensorSpreadMs) ||
    (demandAgeStats.maxAgeMs !== null && demandAgeStats.maxAgeMs > timingThresholds.maxSensorAgeMs);

node.status({
    fill: snapshotLagging ? "yellow" : "blue",
    shape: snapshotLagging ? "ring" : "dot",
    text: `Solar: ${Math.round(proactiveSolar)}W | Demand: ${Math.round(defensiveTarget)}W | sync ${Math.round(
        demandConfidence * 100
    )}%`
});

msg.derived.demand.current = Math.round(currentDemandEstimate);
msg.derived.demand.raw = Math.round(currentDemandRaw);
msg.derived.demand.average = Math.round(averageDemand);
msg.derived.demand.median = Math.round(medianDemand);
msg.derived.demand.lowerBound = Math.round(demandLowerBound);
msg.derived.demand.longTermMinimum = Math.round(demandLongTermMinimum);
msg.derived.demand.defensiveTarget = Math.round(defensiveTarget - flowBias);
msg.derived.demand.stdDev = Math.round(demandStdDev);
msg.derived.demand.trend = Math.round(demandTrend);
msg.derived.demand.trendDirection = demandTrendDirection;
msg.derived.demand.trendChanges = demandTrendChanges;
msg.derived.solar.livePower = Math.round(proactiveSolar);
msg.derived.solar.rawPower = Math.round(currentSolarRaw);
msg.derived.solar.averagePower = Math.round(averageSolar);
msg.derived.solar.stdDev = Math.round(solarStdDev);
msg.derived.solar.trend = Math.round(solarTrend);
msg.derived.solar.trendDirection = solarTrendDirection;
msg.derived.solar.trendChanges = solarTrendChanges;
msg.meta.sensorTiming = {
    thresholds: timingThresholds,
    demand: {
        confidence: Math.round(demandConfidence * 100) / 100,
        currentRaw: Math.round(currentDemandRaw),
        currentEstimate: Math.round(currentDemandEstimate),
        minAgeMs: demandAgeStats.minAgeMs,
        maxAgeMs: demandAgeStats.maxAgeMs,
        spreadMs: demandAgeStats.spreadMs,
        sensors: {
            grid: gridReading,
            batteryDischarge: batteryDischargeReading,
            solarPrimary: solarPrimaryReading,
            solarSecondary: solarSecondaryReading,
            batteryCharge: batteryChargeReading
        }
    },
    solar: {
        confidence: Math.round(solarConfidence * 100) / 100,
        currentRaw: Math.round(currentSolarRaw),
        currentEstimate: Math.round(currentSolarEstimate),
        minAgeMs: solarAgeStats.minAgeMs,
        maxAgeMs: solarAgeStats.maxAgeMs,
        spreadMs: solarAgeStats.spreadMs,
        sensors: {
            solarPrimary: solarPrimaryReading,
            solarSecondary: solarSecondaryReading
        }
    }
};
msg.meta.stability = {
    mode: stabilityMode,
    demand: demandStability,
    solar: solarStability,
    thresholds: stabilityThresholds,
    stats: {
        demandAverage: Math.round(averageDemand),
        demandLowerBound: Math.round(demandLowerBound),
        demandLongTermMinimum: Math.round(demandLongTermMinimum),
        demandStdDev: Math.round(demandStdDev),
        demandTrend: Math.round(demandTrend),
        demandTrendDirection,
        demandTrendChanges,
        solarAverage: Math.round(averageSolar),
        solarStdDev: Math.round(solarStdDev),
        solarTrend: Math.round(solarTrend),
        solarTrendDirection,
        solarTrendChanges
    }
};
msg.meta.history = {
    windowSeconds: historyWindowSeconds,
    triggerIntervalSeconds: triggerIntervalSeconds,
    triggerIntervalMs: triggerIntervalSeconds * 1000,
    samples: historySamples
};
return msg;

function hasMessageValue(root, path) {
    let current = root;
    for (const segment of path.split(".")) {
        if (
            current === null ||
            current === undefined ||
            !Object.prototype.hasOwnProperty.call(current, segment)
        ) {
            return false;
        }
        current = current[segment];
    }
    return current !== undefined && current !== null;
}

function abortForMissing(requiredPaths) {
    const missing = requiredPaths.filter((path) => !hasMessageValue(msg, path));
    if (missing.length === 0) {
        return false;
    }

    const errorMessage = `Missing mandatory message fields: ${missing.join(", ")}`;
    node.status({ fill: "red", shape: "ring", text: `Missing data: ${missing.join(", ")}` });
    node.error(errorMessage, msg);
    return true;
}

function parseTimestampMs(value) {
    if (typeof value !== "string" || value.trim() === "") {
        return null;
    }

    const timestampMs = new Date(value).getTime();
    return Number.isFinite(timestampMs) ? timestampMs : null;
}

if (
    abortForMissing(["data.battery.availableWh", "data.forecast.nextHourWh", "data.sun.nextRising"])
) {
    return null;
}

const data = msg.data;

// 1. DATA EXTRACTION
const availableWh = data.battery.availableWh;

// 2. NEXT HOUR FORECAST (Wh expected in the next 60 mins)
const totalNextHourWh = data.forecast.nextHourWh;

// 3. TIME CALCULATION
const now = new Date().getTime();
const sunrise = parseTimestampMs(data.sun.nextRising);

if (sunrise === null) {
    const errorMessage = `Invalid sunrise timestamp: ${data.sun.nextRising}`;
    node.status({ fill: "red", shape: "ring", text: "Invalid sunrise timestamp" });
    node.error(errorMessage, msg);
    return null;
}

// 4. DYNAMIC WINDOW ADJUSTMENT
let hoursToUsableSolar = Math.max(0.5, (sunrise - now) / (1000 * 60 * 60));
let budgetWindowReason = "sunrise";

// If the Next Hour forecast is already > 100Wh, the sun is effectively "up"
// for the battery logic, even if the clock says it's early.
if (totalNextHourWh > 100) {
    // Sun is strong! Shorten the window to 1 hour to empty the battery faster.
    hoursToUsableSolar = 1.0;
    budgetWindowReason = "usable solar";
} else if (totalNextHourWh > 20) {
    // Sun is starting to peek through.
    hoursToUsableSolar = Math.min(hoursToUsableSolar, 2.0);
    budgetWindowReason = hoursToUsableSolar === 2.0 ? "early solar" : "sunrise";
}

// Handle edge case: If it's 2 AM and sunrise is 6 AM, hoursToSunrise = 4.
// If sunrise has already passed, default to a small number to avoid division by zero.
// Math.max ensures we don't get negative numbers if sunrise just happened.
const hoursToSunrise = Math.max(0.5, (sunrise - now) / (1000 * 60 * 60));

// 3. CALCULATION
const usableWh = Math.max(0, availableWh);
const forcedRate = Math.round(usableWh / hoursToUsableSolar);

// 4. PASS IT FORWARD
msg.derived = msg.derived || {};
msg.derived.forecast = msg.derived.forecast || {};
msg.derived.forecast.nextHourWh = totalNextHourWh;
msg.derived.forecast.hoursToUsableSolar = Number(hoursToUsableSolar.toFixed(1));
msg.derived.forecast.hoursToSunrise = hoursToSunrise.toFixed(1);
msg.derived.forecast.budgetWindowReason = budgetWindowReason;
msg.action = msg.action || {};
msg.action.battery = msg.action.battery || {};
msg.action.battery.discharge = msg.action.battery.discharge || {};
msg.action.battery.discharge.forcedRate = forcedRate;

node.status({
    fill: "blue",
    shape: "ring",
    text: `Budget: forced ${forcedRate}W over ${hoursToUsableSolar.toFixed(1)}h (${budgetWindowReason})`
});

return msg;

function hasMessageValue(root, path) {
    let current = root;
    for (const segment of path.split(".")) {
        if (
            current === null ||
            current === undefined ||
            !Object.prototype.hasOwnProperty.call(current, segment)
        ) {
            return false;
        }
        current = current[segment];
    }
    return current !== undefined;
}

function abortForMissing(requiredPaths) {
    const missing = requiredPaths.filter((path) => !hasMessageValue(msg, path));
    if (missing.length === 0) {
        return false;
    }

    const errorMessage = `Missing mandatory message fields: ${missing.join(", ")}`;
    node.status({ fill: "red", shape: "ring", text: `Missing data: ${missing.join(", ")}` });
    node.error(errorMessage, msg);
    return true;
}

if (
    abortForMissing([
        "data.grid.power",
        "data.battery.dischargePower",
        "derived.demand.defensiveTarget",
        "derived.demand.lowerBound",
        "derived.demand.longTermMinimum",
        "derived.solar.livePower",
        "action.battery.discharge.forcedRate"
    ])
) {
    return null;
}

// 1. DATA RETRIEVAL
const data = msg.data;
const derived = msg.derived;
const action = msg.action;
const gridPower = data.grid.power;
const currentBatteryOut = data.battery.dischargePower;
const calculatedDemand = derived.demand.defensiveTarget;
const demandLowerBound = derived.demand.lowerBound;
const demandLongTermMinimum = derived.demand.longTermMinimum;
const solarPower = derived.solar.livePower;
const forcedDischarge = action.battery.discharge.forcedRate;
const stopRequested = action.battery.discharge.stopRequested === true;
const blockedByLowSoc = action.battery.discharge.blockedByLowSoc === true;
const stability = msg.meta?.stability || {};
const demandTrend = Number.isFinite(derived.demand.trend) ? derived.demand.trend : 0;

if (stopRequested || blockedByLowSoc) {
    context.set("lastCommand", 0);

    msg.action = action;
    msg.action.battery = msg.action.battery || {};
    msg.action.battery.discharge = msg.action.battery.discharge || {};
    msg.action.battery.discharge.commandPower = 0;
    msg.action.battery.discharge.requiredChange = 0;
    msg.action.battery.discharge.isStable = true;
    msg.action.battery.discharge.gridPower = Math.round(gridPower);

    node.status({
        fill: "red",
        shape: "ring",
        text: blockedByLowSoc ? "Discharge blocked by low SoC" : "Discharge stop requested"
    });
    return msg;
}

// 2. CONFIGURATION (Based on safety buffer strategy)
// this addresses the "Moving Target" problem with huge latencies of smart meter and battery chargine changes:
//   1. The Deadband(deadband = 75): This is your Cycle - Killer.
//                                   It stops the battery from chasing the "ghosts" of small appliances.
//                                   If your fridge compressor flickers, the battery ignores it.
//
//   2. The Safety Buffer(-30): By aiming for a 30W import, you create a "cushion."
//                              When a cloud disappears and solar spikes, you have 30W of "room" before
//                              starting to feed-in into public grid.
//
//   3. The EMA(alpha = 0.9): This solves the 50s latency of smart meter and battery.
//                            Instead of jumping to a new value every 20s (init trigger) and
//                            overshooting, the battery "slides" toward the new value. This reduces the
//                            chemical stress on the LiFePO4 cells.

const conservativeImportBuffer = 50; // Aim for 50W import when statistics are unstable
const efficientImportBuffer = 10; // Use a tighter buffer when stable-stable statistics are available
const stableStableMode =
    stability.mode === "stable_stable" ||
    (stability.demand === "stable" && stability.solar === "stable");
const targetImportBuffer = stableStableMode ? efficientImportBuffer : conservativeImportBuffer;
const targetBuffer = -targetImportBuffer;
const deadband = 50; // Ignore fluctuations smaller than 50W
const alpha = 0.3; // EMA Smoothing factor (0.1 = very slow, 0.9 = very fast)
const sustainTolerance = 30; // Treat demand near the lower bound as baseline night load
const importHoldThreshold = targetImportBuffer; // Do not reduce active discharge while import is above target

// 3. CALCULATION
// calculated Demand is the brutto demand of power, solar power the generated and usable power.
// default expects, that there is more solar power than demand,
// e.g. 10W (solar) - 300W (demand) - (-30) = -260W to discharge
//       0W (solar) - 50W (demand) - (-30) = -20W to discharge
//     100W (solar) - 200W (demand) - (-30) = -70W to discharge
//       0W (solar) - 200W (demand) - (-30) = -170W to discharge
//       1W (solar) - 201W (demand) - (-30) = -170W to discharge
//       0W (solar) - (-50)W (demand) - (-30) = 80W to adjust or even stop discharging (discharging is at least 50W)
let requiredChange = solarPower - calculatedDemand - targetBuffer;

// 4. THE CYCLE GUARD (Dynamic Deadband)
// If the requiredChange is small AND we aren't "exporting", stay still to save battery cycles
if (Math.abs(requiredChange) < deadband && gridPower > 0 && currentBatteryOut == 0) {
    node.status({
        fill: "green",
        shape: "dot",
        text: `Done (deadband) - Stable power - finish (calculated change is ${Math.round(requiredChange)}W, grid power: ${Math.round(gridPower)}W)`
    });
    return null; // Stop the message here; no command sent to inverter
}

// 5. EMA SMOOTHING (The "Lag Compensator")
let lastCommand = context.get("lastCommand") || 0;
let rawCommand = requiredChange * -1; // invert to represent the power gap required from battery

if (rawCommand < 0 && currentBatteryOut > 0) {
    // demand is larger than solar power but still solar power available
    rawCommand = (requiredChange - targetBuffer - currentBatteryOut) * -1; // 80W - 30 - 60 = -10 -> reduce discharging before stopping
}

// Apply Exponential Moving Average
let smoothedCommand = rawCommand * alpha + lastCommand * (1 - alpha);

const activeDischargeReference = Math.max(currentBatteryOut, lastCommand);
const isDischargingActive = activeDischargeReference > 5;
const baselineDemandFloor = Math.max(demandLowerBound, demandLongTermMinimum);
const isAtDemandFloor = calculatedDemand <= baselineDemandFloor + sustainTolerance;
const lowerBoundDischargeFloor = Math.max(0, baselineDemandFloor - solarPower);
const dischargeSustainFloor = Math.min(
    forcedDischarge,
    activeDischargeReference,
    lowerBoundDischargeFloor
);
const sustainDischargeActive =
    isDischargingActive &&
    forcedDischarge > 0 &&
    gridPower > 0 &&
    isAtDemandFloor &&
    dischargeSustainFloor > 0;

if (sustainDischargeActive && smoothedCommand < dischargeSustainFloor) {
    smoothedCommand = dischargeSustainFloor;
}

if (stableStableMode && isDischargingActive && gridPower >= 0) {
    const gridError = gridPower - targetImportBuffer;
    const gridTrendCorrection = gridError + demandTrend;
    const gridTrendCommand = activeDischargeReference + gridTrendCorrection * alpha;

    if (gridTrendCorrection > 0) {
        smoothedCommand = Math.max(smoothedCommand, gridTrendCommand);
    } else if (gridTrendCorrection < 0) {
        smoothedCommand = Math.min(smoothedCommand, gridTrendCommand);
    }

    if (sustainDischargeActive && smoothedCommand < dischargeSustainFloor) {
        smoothedCommand = dischargeSustainFloor;
    }
}

const importHoldActive =
    isDischargingActive &&
    gridPower >= importHoldThreshold &&
    smoothedCommand < activeDischargeReference;

if (importHoldActive) {
    smoothedCommand = activeDischargeReference;
}

// 5. THE ZERO-EXPORT DEFENSE (The "No-Penalty" Guard)
// --> EMERGENCY BRAKE
if (gridPower < 0) {
    smoothedCommand = Math.max(0, currentBatteryOut + gridPower + targetBuffer);
}

smoothedCommand = Math.min(smoothedCommand, forcedDischarge * 2.5);

// Only output if the command actually changed significantly (e.g., > 5W)
if (Math.abs(smoothedCommand - lastCommand) < 5 && gridPower > 0 && currentBatteryOut == 0) {
    node.status({
        fill: "green",
        shape: "dot",
        text: `Idle (deadband) - Hardly changed power - finish: ${Math.round(smoothedCommand)}W, grid Power ${gridPower}W`
    });
    return null;
}

// 6. FINAL OUTPUT & PERSISTENCE
context.set("lastCommand", smoothedCommand);

msg.action = action;
msg.action.battery = msg.action.battery || {};
msg.action.battery.discharge = msg.action.battery.discharge || {};
msg.action.battery.discharge.commandPower = Math.round(smoothedCommand);
msg.action.battery.discharge.requiredChange = Math.round(requiredChange);
msg.action.battery.discharge.isStable = Math.abs(requiredChange) < deadband;
msg.action.battery.discharge.gridPower = Math.round(gridPower);
msg.action.battery.discharge.baselineDemandFloor = Math.round(baselineDemandFloor);
msg.action.battery.discharge.sustainFloor = Math.round(dischargeSustainFloor);
msg.action.battery.discharge.sustainActive = sustainDischargeActive;
msg.action.battery.discharge.importHoldActive = importHoldActive;
msg.action.battery.discharge.targetImportBuffer = targetImportBuffer;

node.status({
    fill: "green",
    shape: "dot",
    text: importHoldActive
        ? `Discharge import hold @ ${Math.round(smoothedCommand)}W`
        : sustainDischargeActive
          ? `Discharge sustain @ ${Math.round(smoothedCommand)}W`
          : `Calculated Power (smoothed): ${Math.round(smoothedCommand)}W`
});
return msg;
